import React, { createContext, useState, useContext, useEffect, useCallback } from 'react';

type ThemeMode = 'light' | 'dark';

interface ThemeColors {
  primary: string;
  secondary: string;
  background: string;
  text: string;
  border: string;
}

const defaultThemes: Record<ThemeMode, ThemeColors> = {
  light: {
    primary: '#3b82f6',
    secondary: '#6366f1',
    background: '#ffffff',
    text: '#1f2937',
    border: '#e5e7eb',
  },
  dark: {
    primary: '#60a5fa',
    secondary: '#818cf8',
    background: '#111827',
    text: '#f9fafb',
    border: '#374151',
  },
};

interface ThemeContextValue {
  mode: ThemeMode;
  colors: ThemeColors;
  toggleTheme: () => void;
  setCustomTheme: (colors: Partial<ThemeColors>) => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function useTheme() {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within ThemeProvider');
  return context;
}

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [mode, setMode] = useState<ThemeMode>(
    localStorage.getItem('theme-mode') as ThemeMode || 'light'
  );
  const [customOverrides, setCustomOverrides] = useState<Partial<ThemeColors>>({});

  useEffect(() => {
    localStorage.setItem('theme-mode', mode);
  }, [mode]);

  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');

    const handler = (e: MediaQueryListEvent) => {
      if (!localStorage.getItem('theme-mode')) {
        setMode(e.matches ? 'dark' : 'light');
      }
    };

    mediaQuery.addEventListener('change', handler);
  }, []);

  useEffect(() => {
    const colors = { ...defaultThemes[mode], ...customOverrides };
    const root = document.documentElement;
    Object.entries(colors).forEach(([key, value]) => {
      root.style.setProperty(`--color-${key}`, value);
    });
  }, [mode, customOverrides]);

  const toggleTheme = () => {
    setMode(prev => prev === 'light' ? 'dark' : 'light');
  };

  const setCustomTheme = (overrides: Partial<ThemeColors>) => {
    setCustomOverrides(prev => ({ ...prev, ...overrides }));
  };

  const colors = { ...defaultThemes[mode], ...customOverrides };

  return (
    <ThemeContext.Provider value={ {
      mode,
      colors,
      toggleTheme,
      setCustomTheme,
    } }>
      {children}
    </ThemeContext.Provider>
  );
}

